/**
 * Google Ads API client (REST + GAQL via fetch).
 *
 * Phase 1 scope: READ-ONLY.
 *   - OAuth 2 access-token refresh
 *   - GAQL search (campaigns, ad-group metrics, search terms)
 *   - Keyword Plan idea service (for the agent's keyword research loop)
 *
 * Phase 2/3 will add mutation paths (create campaign / ad group / RSA / keyword)
 * behind the spend-guard + approval gate. Do not add mutation code here without
 * landing those pieces first.
 *
 * Why hand-rolled fetch instead of the `google-ads-api` npm package?
 *   - Avoids pulling in a heavy dependency chain (gRPC, protobuf) for what is
 *     fundamentally a JSON-over-HTTPS API at the transport layer.
 *   - GAQL is a string the caller composes; the package adds a query builder
 *     we don't need.
 *   - Easier to audit (no opaque protobuf serialisation in the call path).
 */

import prisma from "@/lib/db";

const API_BASE = "https://googleads.googleapis.com/v24";
const OAUTH_TOKEN_URL = "https://oauth2.googleapis.com/token";
const SCOPE = "https://www.googleapis.com/auth/adwords";

// =========================================================================
// DB-backed API config (falls back to environment variables)
// =========================================================================

export interface GoogleAdsApiConfigShape {
  developerToken: string;
  oauthClientId: string;
  oauthClientSecret: string;
  loginCustomerId: string;
  redirectUri: string;
}

/** Returns API credentials, preferring the DB row over env vars. */
export async function getGoogleAdsApiConfig(): Promise<GoogleAdsApiConfigShape | null> {
  const row = await prisma.googleAdsApiConfig.findUnique({ where: { key: "default" } }).catch(() => null);

  const developerToken    = row?.developerToken    || process.env.GOOGLE_ADS_DEVELOPER_TOKEN    || "";
  const oauthClientId     = row?.oauthClientId     || process.env.GOOGLE_ADS_OAUTH_CLIENT_ID     || "";
  const oauthClientSecret = row?.oauthClientSecret || process.env.GOOGLE_ADS_OAUTH_CLIENT_SECRET || "";
  const loginCustomerId   = row?.loginCustomerId   || process.env.GOOGLE_ADS_LOGIN_CUSTOMER_ID   || "";
  const redirectUri       = row?.redirectUri       || process.env.GOOGLE_ADS_OAUTH_REDIRECT_URI  || "";

  if (!developerToken || !oauthClientId || !oauthClientSecret || !loginCustomerId || !redirectUri) {
    return null;
  }
  return { developerToken, oauthClientId, oauthClientSecret, loginCustomerId, redirectUri };
}

/** Returns true when at least the OAuth client creds are available (for the connect button). */
export async function isGoogleAdsConfigured(): Promise<boolean> {
  const cfg = await getGoogleAdsApiConfig();
  return !!(cfg?.oauthClientId && cfg?.oauthClientSecret);
}

// =========================================================================
// Types
// =========================================================================

export interface GoogleAdsCampaignRow {
  campaignId: string;
  campaignName: string;
  status: string; // ENABLED, PAUSED, REMOVED, UNKNOWN
  advertisingChannelType: string; // SEARCH, DISPLAY, VIDEO, PERFORMANCE_MAX, ...
  // Aggregated metrics for the requested date range
  impressions: number;
  clicks: number;
  costMicros: number; // micros = currency * 1_000_000
  conversions: number;
  conversionsValue: number;
  ctr: number;
  averageCpc: number; // micros
}

export interface GoogleAdsSearchTermRow {
  campaignId: string;
  campaignName: string;
  adGroupId: string;
  adGroupName: string;
  searchTerm: string;
  status: string; // ADDED, EXCLUDED, ADDED_EXCLUDED, NONE, UNKNOWN
  impressions: number;
  clicks: number;
  costMicros: number;
  conversions: number;
}

export interface DateRange {
  /** YYYY-MM-DD inclusive. */
  since: string;
  /** YYYY-MM-DD inclusive. */
  until: string;
}

// =========================================================================
// OAuth helpers
// =========================================================================

interface RefreshedToken {
  accessToken: string;
  expiresAt: Date;
  scope?: string;
}

/**
 * Exchange a long-lived refresh token for a short-lived access token.
 * Called transparently by `GoogleAdsClient` on every API call when the cached
 * token is within 60 s of expiry.
 */
export async function refreshAccessToken(refreshToken: string): Promise<RefreshedToken> {
  const cfg = await getGoogleAdsApiConfig();
  const clientId     = cfg?.oauthClientId     || process.env.GOOGLE_ADS_OAUTH_CLIENT_ID;
  const clientSecret = cfg?.oauthClientSecret || process.env.GOOGLE_ADS_OAUTH_CLIENT_SECRET;
  if (!clientId || !clientSecret) {
    throw new Error("Google Ads OAuth client not configured (set GOOGLE_ADS_OAUTH_CLIENT_ID / _SECRET)");
  }

  const body = new URLSearchParams({
    client_id: clientId,
    client_secret: clientSecret,
    refresh_token: refreshToken,
    grant_type: "refresh_token",
  });

  const res = await fetch(OAUTH_TOKEN_URL, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body,
  });

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Google OAuth refresh failed (${res.status}): ${text}`);
  }

  const json = (await res.json()) as {
    access_token: string;
    expires_in: number;
    scope?: string;
  };
  return {
    accessToken: json.access_token,
    expiresAt: new Date(Date.now() + (json.expires_in - 60) * 1000),
    scope: json.scope,
  };
}

/**
 * Exchange an OAuth authorization code (from the consent-screen redirect) for
 * a refresh token + access token. Called from the OAuth callback route.
 */
export async function exchangeAuthCode(code: string, redirectUri: string): Promise<{
  refreshToken: string;
  accessToken: string;
  expiresAt: Date;
  scope?: string;
}> {
  const cfg = await getGoogleAdsApiConfig();
  const clientId     = cfg?.oauthClientId     || process.env.GOOGLE_ADS_OAUTH_CLIENT_ID;
  const clientSecret = cfg?.oauthClientSecret || process.env.GOOGLE_ADS_OAUTH_CLIENT_SECRET;
  if (!clientId || !clientSecret) {
    throw new Error("Google Ads OAuth client not configured");
  }

  const body = new URLSearchParams({
    client_id: clientId,
    client_secret: clientSecret,
    code,
    redirect_uri: redirectUri,
    grant_type: "authorization_code",
  });

  const res = await fetch(OAUTH_TOKEN_URL, {
    method: "POST",
    headers: { "Content-Type": "application/x-www-form-urlencoded" },
    body,
  });

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`Google OAuth code exchange failed (${res.status}): ${text}`);
  }

  const json = (await res.json()) as {
    access_token: string;
    refresh_token?: string;
    expires_in: number;
    scope?: string;
  };

  if (!json.refresh_token) {
    // Google only returns refresh_token on first consent OR when prompt=consent
    // is supplied; the OAuth start route forces prompt=consent so this should
    // not happen in normal flow.
    throw new Error(
      "Google did not return a refresh_token. Ensure prompt=consent and access_type=offline are set on the auth URL.",
    );
  }

  return {
    refreshToken: json.refresh_token,
    accessToken: json.access_token,
    expiresAt: new Date(Date.now() + (json.expires_in - 60) * 1000),
    scope: json.scope,
  };
}

/**
 * Build the consent-screen URL the user is redirected to in order to grant
 * the platform access to their Google Ads account.
 */
export async function buildAuthUrl(redirectUri: string, state: string): Promise<string> {
  const cfg = await getGoogleAdsApiConfig();
  const clientId = cfg?.oauthClientId || process.env.GOOGLE_ADS_OAUTH_CLIENT_ID;
  if (!clientId) {
    throw new Error("Google Ads OAuth client not configured");
  }
  const params = new URLSearchParams({
    client_id: clientId,
    redirect_uri: redirectUri,
    response_type: "code",
    scope: SCOPE,
    access_type: "offline",
    // Force the consent screen so a refresh_token is always returned, even if
    // the user previously authorised this client.
    prompt: "consent",
    include_granted_scopes: "true",
    state,
  });
  return `https://accounts.google.com/o/oauth2/v2/auth?${params.toString()}`;
}

// =========================================================================
// GoogleAdsClient
// =========================================================================

interface GoogleAdsClientConfig {
  /** 10-digit customer ID, no dashes. */
  customerId: string;
  /** Long-lived OAuth 2 refresh token. */
  refreshToken: string;
  /** Optional cached access token (skips a refresh round-trip). */
  accessToken?: string;
  accessTokenExpiresAt?: Date;
  /**
   * MCC manager ID (digits only). Sent as login-customer-id header. Defaults
   * to env GOOGLE_ADS_LOGIN_CUSTOMER_ID.
   */
  loginCustomerId?: string;
}

export class GoogleAdsClient {
  private readonly customerId: string;
  private readonly refreshToken: string;
  private readonly loginCustomerId?: string;
  private accessToken?: string;
  private accessTokenExpiresAt?: Date;

  constructor(config: GoogleAdsClientConfig) {
    this.customerId = stripDashes(config.customerId);
    this.refreshToken = config.refreshToken;
    this.accessToken = config.accessToken;
    this.accessTokenExpiresAt = config.accessTokenExpiresAt;
    this.loginCustomerId = stripDashes(
      config.loginCustomerId ?? process.env.GOOGLE_ADS_LOGIN_CUSTOMER_ID ?? "",
    );
  }

  /** Returns a valid access token, refreshing if expired. */
  async getAccessToken(): Promise<string> {
    if (
      this.accessToken &&
      this.accessTokenExpiresAt &&
      this.accessTokenExpiresAt.getTime() > Date.now()
    ) {
      return this.accessToken;
    }
    const fresh = await refreshAccessToken(this.refreshToken);
    this.accessToken = fresh.accessToken;
    this.accessTokenExpiresAt = fresh.expiresAt;
    return this.accessToken;
  }

  /**
   * Fetch with burst-429 retry. Google Ads has two distinct 429 modes:
   *   1. Per-minute / per-second burst — short retryDelay (seconds). Retry.
   *   2. Daily quota exhausted (Basic access) — retryDelay = thousands of
   *      seconds. No point retrying within this request.
   *
   * Pattern: try once. On 429, parse the body for `retryDelay`. If it parses
   * to ≤30 seconds, sleep + retry up to 2 more times with exponential
   * backoff. Otherwise rethrow immediately so the caller fails fast.
   *
   * Added 2026-06-10 after Basic-access daily quota was burned by morning
   * diagnostics. Standard access (applied for separately) raises the daily
   * cap by ~70x and most of this stops mattering — but the burst-retry
   * still helps under sustained load.
   */
  private async fetchWithBurstRetry(
    url: string,
    init: RequestInit,
    maxRetries = 2,
  ): Promise<Response> {
    let backoffMs = 1000;
    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      const res = await fetch(url, init);
      if (res.status !== 429) return res;

      // 429 — read body without consuming the stream the caller needs.
      const text = await res.clone().text();
      const retryMatch = text.match(/Retry in (\d+) seconds/);
      const retrySeconds = retryMatch ? Number(retryMatch[1]) : null;

      // Daily quota: retryDelay is huge (hours). Don't retry — let the caller
      // surface the error so admins know to wait or upgrade.
      if (retrySeconds !== null && retrySeconds > 30) return res;
      // Already at last attempt — return the 429 so the caller throws normally.
      if (attempt === maxRetries) return res;

      await new Promise((resolve) => setTimeout(resolve, backoffMs));
      backoffMs *= 2; // 1s → 2s → 4s
    }
    // Unreachable; keep TS happy.
    return fetch(url, init);
  }

  /**
   * Run a GAQL query and return the raw `results` array. Handles pagination
   * via `nextPageToken` transparently (cap = 5 pages to avoid runaway costs;
   * widen if a legitimate report needs more).
   */
  async query<T = unknown>(gaql: string): Promise<T[]> {
    const cfg = await getGoogleAdsApiConfig();
    const developerToken = cfg?.developerToken || process.env.GOOGLE_ADS_DEVELOPER_TOKEN;
    if (!developerToken) {
      throw new Error("GOOGLE_ADS_DEVELOPER_TOKEN not configured");
    }
    const accessToken = await this.getAccessToken();
    const url = `${API_BASE}/customers/${this.customerId}/googleAds:search`;

    const headers: Record<string, string> = {
      Authorization: `Bearer ${accessToken}`,
      "developer-token": developerToken,
      "Content-Type": "application/json",
    };
    if (this.loginCustomerId) {
      headers["login-customer-id"] = this.loginCustomerId;
    }

    const allResults: T[] = [];
    let pageToken: string | undefined;
    const MAX_PAGES = 5;

    for (let page = 0; page < MAX_PAGES; page++) {
      const body: Record<string, unknown> = { query: gaql };
      if (pageToken) body.pageToken = pageToken;

      const res = await this.fetchWithBurstRetry(url, {
        method: "POST",
        headers,
        body: JSON.stringify(body),
      });

      if (!res.ok) {
        const text = await res.text();
        // Map common auth failures to actionable, agent-friendly messages so
        // the LLM stops retrying credential issues every heartbeat cycle.
        if (res.status === 401) {
          throw new Error(
            `Google Ads NOT_AUTHENTICATED (401) for customer ${this.customerId}: refresh token is invalid or expired. ` +
            `This is an infrastructure credential issue — DO NOT retry this tool until an admin re-authorises Google Ads via the OAuth consent flow. ` +
            `Raw response: ${text.slice(0, 200)}`,
          );
        }
        if (res.status === 403) {
          throw new Error(
            `Google Ads PERMISSION_DENIED (403) for customer ${this.customerId}: developer token / login-customer-id mismatch. ` +
            `DO NOT retry — admin intervention required. Raw: ${text.slice(0, 200)}`,
          );
        }
        throw new Error(
          `Google Ads search failed (${res.status}) for customer ${this.customerId}: ${text}`,
        );
      }

      const json = (await res.json()) as {
        results?: T[];
        nextPageToken?: string;
      };
      if (json.results) allResults.push(...json.results);
      if (!json.nextPageToken) break;
      pageToken = json.nextPageToken;
    }

    return allResults;
  }

  /**
   * List campaigns with aggregated metrics for the given date range.
   */
  async getCampaignMetrics(range: DateRange): Promise<GoogleAdsCampaignRow[]> {
    assertDateRange(range);
    const gaql = `
      SELECT
        campaign.id,
        campaign.name,
        campaign.status,
        campaign.advertising_channel_type,
        metrics.impressions,
        metrics.clicks,
        metrics.cost_micros,
        metrics.conversions,
        metrics.conversions_value,
        metrics.ctr,
        metrics.average_cpc
      FROM campaign
      WHERE segments.date BETWEEN '${range.since}' AND '${range.until}'
        AND campaign.status != 'REMOVED'
      ORDER BY metrics.cost_micros DESC
    `;
    const rows = await this.query<{
      campaign: { id: string; name: string; status: string; advertisingChannelType: string };
      metrics: {
        impressions?: string;
        clicks?: string;
        costMicros?: string;
        conversions?: number;
        conversionsValue?: number;
        ctr?: number;
        averageCpc?: string;
      };
    }>(gaql);

    return rows.map((r) => ({
      campaignId: r.campaign.id,
      campaignName: r.campaign.name,
      status: r.campaign.status,
      advertisingChannelType: r.campaign.advertisingChannelType,
      impressions: Number(r.metrics.impressions ?? 0),
      clicks: Number(r.metrics.clicks ?? 0),
      costMicros: Number(r.metrics.costMicros ?? 0),
      conversions: Number(r.metrics.conversions ?? 0),
      conversionsValue: Number(r.metrics.conversionsValue ?? 0),
      ctr: Number(r.metrics.ctr ?? 0),
      averageCpc: Number(r.metrics.averageCpc ?? 0),
    }));
  }

  /**
   * Search Terms Report for a given campaign (or all campaigns if omitted).
   * Used by the agent's keyword-expansion loop in Phase 3.
   */
  async getSearchTermsReport(
    range: DateRange,
    campaignId?: string,
  ): Promise<GoogleAdsSearchTermRow[]> {
    assertDateRange(range);
    const campaignFilter = campaignId
      ? `AND campaign.id = ${asInt(campaignId)}`
      : "";
    const gaql = `
      SELECT
        campaign.id,
        campaign.name,
        ad_group.id,
        ad_group.name,
        search_term_view.search_term,
        search_term_view.status,
        metrics.impressions,
        metrics.clicks,
        metrics.cost_micros,
        metrics.conversions
      FROM search_term_view
      WHERE segments.date BETWEEN '${range.since}' AND '${range.until}'
        ${campaignFilter}
      ORDER BY metrics.cost_micros DESC
    `;
    const rows = await this.query<{
      campaign: { id: string; name: string };
      adGroup: { id: string; name: string };
      searchTermView: { searchTerm: string; status: string };
      metrics: {
        impressions?: string;
        clicks?: string;
        costMicros?: string;
        conversions?: number;
      };
    }>(gaql);

    return rows.map((r) => ({
      campaignId: r.campaign.id,
      campaignName: r.campaign.name,
      adGroupId: r.adGroup.id,
      adGroupName: r.adGroup.name,
      searchTerm: r.searchTermView.searchTerm,
      status: r.searchTermView.status,
      impressions: Number(r.metrics.impressions ?? 0),
      clicks: Number(r.metrics.clicks ?? 0),
      costMicros: Number(r.metrics.costMicros ?? 0),
      conversions: Number(r.metrics.conversions ?? 0),
    }));
  }

  // =======================================================================
  // Mutation helpers (Phase 2+)
  //
  // These wrap the {resource}:mutate REST endpoints. All mutations create
  // PAUSED entities by default — caller must explicitly enable. This is
  // belt-and-braces so an accidental publish never starts spending.
  // =======================================================================

  /** Customer ID without dashes — exposed for callers building resource names. */
  get customerIdPlain(): string {
    return this.customerId;
  }

  /**
   * Low-level mutation primitive. POSTs to `customers/{cid}/{resource}:mutate`
   * with the supplied operations. Returns the parsed JSON body. Caller is
   * responsible for the operation shape — see the high-level wrappers below.
   */
  async mutate<T = unknown>(
    resource: string,
    operations: Record<string, unknown>[],
    options: { partialFailure?: boolean; validateOnly?: boolean } = {},
  ): Promise<T> {
    // Prefer DB-stored developer token over env var so admin UI changes take effect immediately.
    const cfg = await getGoogleAdsApiConfig().catch(() => null);
    const developerToken = cfg?.developerToken || process.env.GOOGLE_ADS_DEVELOPER_TOKEN;
    if (!developerToken) {
      throw new Error("GOOGLE_ADS_DEVELOPER_TOKEN not configured");
    }
    if (!operations.length) {
      throw new Error("mutate() called with empty operations array");
    }
    const accessToken = await this.getAccessToken();
    const url = `${API_BASE}/customers/${this.customerId}/${resource}:mutate`;

    const headers: Record<string, string> = {
      Authorization: `Bearer ${accessToken}`,
      "developer-token": developerToken,
      "Content-Type": "application/json",
    };
    if (this.loginCustomerId) {
      headers["login-customer-id"] = this.loginCustomerId;
    }

    const body: Record<string, unknown> = {
      operations,
      partialFailure: options.partialFailure ?? false,
      validateOnly: options.validateOnly ?? false,
    };

    const res = await this.fetchWithBurstRetry(url, {
      method: "POST",
      headers,
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const text = await res.text();
      throw new Error(
        `Google Ads ${resource} mutate failed (${res.status}) for customer ${this.customerId}: ${text}`,
      );
    }
    return (await res.json()) as T;
  }

  /**
   * Generic POST helper for Google Ads API endpoints that are NOT `:mutate`
   * (e.g. `:uploadClickConversions`, `:uploadCallConversions`).
   *
   * Usage:
   *   client.request(`customers/${cid}:uploadClickConversions`, "POST", body)
   *
   * The path is appended to API_BASE. The caller is responsible for the full
   * path segment (e.g. `customers/123:uploadClickConversions`).
   */
  async request<T = unknown>(
    path: string,
    method: string,
    body: Record<string, unknown>,
  ): Promise<T> {
    const cfg = await getGoogleAdsApiConfig().catch(() => null);
    const developerToken = cfg?.developerToken || process.env.GOOGLE_ADS_DEVELOPER_TOKEN;
    if (!developerToken) {
      throw new Error("GOOGLE_ADS_DEVELOPER_TOKEN not configured");
    }
    const accessToken = await this.getAccessToken();
    const url = `${API_BASE}/${path}`;

    const headers: Record<string, string> = {
      Authorization: `Bearer ${accessToken}`,
      "developer-token": developerToken,
      "Content-Type": "application/json",
    };
    if (this.loginCustomerId) {
      headers["login-customer-id"] = this.loginCustomerId;
    }

    const res = await this.fetchWithBurstRetry(url, {
      method,
      headers,
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const text = await res.text();
      throw new Error(
        `Google Ads ${path} ${method} failed (${res.status}): ${text}`,
      );
    }
    return (await res.json()) as T;
  }

  /**
   * Call KeywordPlanIdeaService.generateKeywordIdeas — Google's free keyword
   * research endpoint. Used by the Opportunity Scout to compare CPC /
   * competition / search volume across UK geos without spending a penny.
   *
   * One call = one (geoTargetIds × seeds) cell. Combine geos in one call
   * (Google sums the volumes across them) or call once per geo if you need
   * per-geo numbers — the scout uses per-geo.
   *
   * Quota: KeywordPlan API has a small daily cap; cache aggressively at the
   * caller layer (the scout caches via the GoogleAdsOpportunity table).
   */
  /**
   * Pull Auction Insights for all enabled campaigns — returns competitor
   * domains that are bidding in the same auctions as our ads.
   *
   * Requires at least one ENABLED campaign with sufficient impressions (Google
   * suppresses results with < ~100 auctions). Returns an empty array when there
   * are no active campaigns or insufficient data.
   *
   * GAQL reference: auction_insight resource (segment by campaign or ad_group).
   */
  /**
   * Campaign impression share per geo-target, from live campaigns.
   * Returns a map of geoTargetId → impressionShare (0–1).
   *
   * Used by the Opportunity Scout to know where we already have coverage
   * (high IS = already dominant) vs where we have room to grow (low IS).
   *
   * Requires at least one active campaign with geo-targeting enabled.
   * Returns empty map when no campaigns or insufficient data.
   */
  async getCampaignImpressionShareByGeo(
    range: DateRange,
  ): Promise<Map<string, number>> {
    assertDateRange(range);
    // GAQL: pull impression share segmented by geo_target_constant.
    // geo_target_constant is available on campaign_criterion when geo targeting is set.
    const gaql = `
      SELECT
        campaign_criterion.location.geo_target_constant,
        metrics.search_impression_share,
        metrics.impressions
      FROM campaign_criterion
      WHERE segments.date BETWEEN '${range.since}' AND '${range.until}'
        AND campaign_criterion.type = 'LOCATION'
        AND campaign.status = 'ENABLED'
        AND metrics.impressions > 100
      ORDER BY metrics.search_impression_share DESC
    `;
    try {
      const rows = await this.query<{
        campaignCriterion?: { location?: { geoTargetConstant?: string } };
        metrics?: { searchImpressionShare?: number; impressions?: string };
      }>(gaql);

      const result = new Map<string, number>();
      for (const r of rows) {
        const rawGeo = r.campaignCriterion?.location?.geoTargetConstant ?? "";
        // geoTargetConstant returned as "geoTargetConstants/12345" — extract ID
        const geoId = rawGeo.split("/").pop() ?? "";
        if (!geoId) continue;
        const is = r.metrics?.searchImpressionShare ?? 0;
        // If a geo appears multiple times (multiple campaigns), keep highest IS.
        if (!result.has(geoId) || (result.get(geoId) ?? 0) < is) {
          result.set(geoId, Number(is.toFixed(4)));
        }
      }
      return result;
    } catch (err) {
      console.warn("[GoogleAdsClient] getCampaignImpressionShareByGeo failed:", err instanceof Error ? err.message : err);
      return new Map();
    }
  }

  /**
   * Returns performance metrics segmented by hour of day for enabled campaigns.
   * Used to detect "after-hours gaps" — periods when competitors drop off.
   *
   * Returns array of hourly rows sorted by hour (0–23).
   */
  async getHourlyPerformance(range: DateRange): Promise<HourlyPerformanceRow[]> {
    assertDateRange(range);
    const gaql = `
      SELECT
        segments.hour,
        metrics.impressions,
        metrics.clicks,
        metrics.cost_micros,
        metrics.conversions,
        metrics.search_impression_share
      FROM campaign
      WHERE segments.date BETWEEN '${range.since}' AND '${range.until}'
        AND campaign.status = 'ENABLED'
        AND metrics.impressions > 0
      ORDER BY segments.hour ASC
    `;
    try {
      const rows = await this.query<{
        segments?: { hour?: number };
        metrics?: {
          impressions?: string;
          clicks?: string;
          costMicros?: string;
          conversions?: number;
          searchImpressionShare?: number;
        };
      }>(gaql);

      // Aggregate across all campaigns by hour.
      const byHour = new Map<number, HourlyPerformanceRow>();
      for (const r of rows) {
        const hour = r.segments?.hour ?? 0;
        const existing = byHour.get(hour);
        const impressions = Number(r.metrics?.impressions ?? 0);
        const clicks = Number(r.metrics?.clicks ?? 0);
        const costMicros = Number(r.metrics?.costMicros ?? 0);
        const conversions = Number(r.metrics?.conversions ?? 0);
        const is = r.metrics?.searchImpressionShare ?? 0;
        if (!existing) {
          byHour.set(hour, { hour, impressions, clicks, costMicros, conversions, searchImpressionShare: is });
        } else {
          existing.impressions += impressions;
          existing.clicks += clicks;
          existing.costMicros += costMicros;
          existing.conversions += conversions;
          // Weighted average impression share.
          existing.searchImpressionShare = impressions > 0
            ? (existing.searchImpressionShare * (existing.impressions - impressions) + is * impressions) / existing.impressions
            : existing.searchImpressionShare;
        }
      }
      return [...byHour.values()].sort((a, b) => a.hour - b.hour);
    } catch (err) {
      console.warn("[GoogleAdsClient] getHourlyPerformance failed:", err instanceof Error ? err.message : err);
      return [];
    }
  }

  async getAuctionInsights(range: DateRange): Promise<AuctionInsightRow[]> {
    assertDateRange(range);
    const gaql = `
      SELECT
        auction_insight.domain,
        metrics.impressions,
        auction_insight.overlap_rate,
        auction_insight.position_above_rate,
        auction_insight.top_of_page_rate,
        auction_insight.absolute_top_of_page_rate
      FROM auction_insight
      WHERE segments.date BETWEEN '${range.since}' AND '${range.until}'
        AND campaign.status = 'ENABLED'
      ORDER BY auction_insight.overlap_rate DESC
    `;
    try {
      const rows = await this.query<{
        auctionInsight?: {
          domain?: string;
          overlapRate?: number;
          positionAboveRate?: number;
          topOfPageRate?: number;
          absoluteTopOfPageRate?: number;
        };
        metrics?: { impressions?: string };
      }>(gaql);

      // De-duplicate: GAQL returns one row per (domain × campaign), merge by domain.
      const byDomain = new Map<string, AuctionInsightRow>();
      for (const r of rows) {
        const domain = r.auctionInsight?.domain;
        if (!domain) continue;
        const existing = byDomain.get(domain);
        if (!existing) {
          byDomain.set(domain, {
            domain,
            overlapRate: r.auctionInsight?.overlapRate ?? 0,
            positionAboveRate: r.auctionInsight?.positionAboveRate ?? 0,
            topOfPageRate: r.auctionInsight?.topOfPageRate ?? 0,
            absoluteTopOfPageRate: r.auctionInsight?.absoluteTopOfPageRate ?? 0,
          });
        } else {
          // Keep the highest overlap_rate row (most relevant competitor).
          if ((r.auctionInsight?.overlapRate ?? 0) > existing.overlapRate) {
            byDomain.set(domain, {
              ...existing,
              overlapRate: r.auctionInsight?.overlapRate ?? existing.overlapRate,
              positionAboveRate: r.auctionInsight?.positionAboveRate ?? existing.positionAboveRate,
              topOfPageRate: r.auctionInsight?.topOfPageRate ?? existing.topOfPageRate,
              absoluteTopOfPageRate: r.auctionInsight?.absoluteTopOfPageRate ?? existing.absoluteTopOfPageRate,
            });
          }
        }
      }
      return [...byDomain.values()].sort((a, b) => b.overlapRate - a.overlapRate);
    } catch (err) {
      // Auction insights may not be available on all account types; fail softly.
      console.warn("[GoogleAdsClient] getAuctionInsights failed:", err instanceof Error ? err.message : err);
      return [];
    }
  }

  /**
   * Generate keyword ideas seeded by a competitor's website URL.
   * Uses the `siteSeed` parameter of KeywordPlanIdeaService — Google returns
   * keywords relevant to the site's content. This is useful for discovering
   * locksmith-relevant keyword topics from competitor sites, but it does NOT
   * reveal their paid keyword list, bid strategy, match types, or negative
   * keywords. It is keyword prospecting, not paid-search reverse engineering.
   *
   * Workflow: pass a domain discovered via getAuctionInsights() (i.e., a domain
   * that co-appears in our auctions) to get keyword ideas seeded from their site
   * content. The ideas then go through the Planner volume/CPC pipeline and are
   * filtered by profitability before entering the seed bank.
   */
  async generateKeywordIdeasFromSite(opts: {
    siteUrl: string;          // e.g. "https://locksmiths.co.uk"
    geoTargetIds: string[];
    languageId?: string;
    network?: "GOOGLE_SEARCH" | "GOOGLE_SEARCH_AND_PARTNERS";
    pageSize?: number;
  }): Promise<KeywordIdea[]> {
    if (!opts.geoTargetIds.length) throw new Error("generateKeywordIdeasFromSite: geoTargetIds required");
    if (!opts.siteUrl) throw new Error("generateKeywordIdeasFromSite: siteUrl required");

    const cfg = await getGoogleAdsApiConfig().catch(() => null);
    const developerToken = cfg?.developerToken || process.env.GOOGLE_ADS_DEVELOPER_TOKEN;
    if (!developerToken) throw new Error("GOOGLE_ADS_DEVELOPER_TOKEN not configured");

    const accessToken = await this.getAccessToken();
    const url = `${API_BASE}/customers/${this.customerId}:generateKeywordIdeas`;
    const headers: Record<string, string> = {
      Authorization: `Bearer ${accessToken}`,
      "developer-token": developerToken,
      "Content-Type": "application/json",
    };
    if (this.loginCustomerId) headers["login-customer-id"] = this.loginCustomerId;

    const body = {
      language: `languageConstants/${opts.languageId ?? "1000"}`,
      geoTargetConstants: opts.geoTargetIds.map((g) => `geoTargetConstants/${g}`),
      keywordPlanNetwork: opts.network ?? "GOOGLE_SEARCH",
      // siteSeed tells the Planner to return keywords relevant to the given URL.
      siteSeed: { site: opts.siteUrl },
      pageSize: opts.pageSize ?? 100,
      includeAdultKeywords: false,
    };

    const res = await fetch(url, {
      method: "POST",
      headers,
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const text = await res.text();
      // Site seeds sometimes fail (private/low-traffic sites); fail softly.
      console.warn(
        `[GoogleAdsClient] generateKeywordIdeasFromSite failed (${res.status}) for ${opts.siteUrl}: ${text.slice(0, 200)}`,
      );
      return [];
    }

    const json = (await res.json()) as {
      results?: Array<{
        text?: string;
        keywordIdeaMetrics?: {
          avgMonthlySearches?: string;
          competition?: "UNKNOWN" | "UNSPECIFIED" | "LOW" | "MEDIUM" | "HIGH";
          competitionIndex?: string;
          lowTopOfPageBidMicros?: string;
          highTopOfPageBidMicros?: string;
        };
      }>;
    };

    return (json.results ?? []).map((r) => ({
      text: r.text ?? "",
      avgMonthlySearches: Number(r.keywordIdeaMetrics?.avgMonthlySearches ?? 0),
      competition: (r.keywordIdeaMetrics?.competition ?? "UNKNOWN") as KeywordIdea["competition"],
      competitionIndex: Number(r.keywordIdeaMetrics?.competitionIndex ?? 0),
      lowTopOfPageBidMicros: Number(r.keywordIdeaMetrics?.lowTopOfPageBidMicros ?? 0),
      highTopOfPageBidMicros: Number(r.keywordIdeaMetrics?.highTopOfPageBidMicros ?? 0),
    }));
  }

  async generateKeywordIdeas(opts: {
    geoTargetIds: string[]; // numeric geo constant IDs, e.g. "1006886" (Bristol)
    keywordSeeds: string[]; // e.g. ["locksmith", "emergency locksmith"]
    languageId?: string; // default 1000 = English
    network?: "GOOGLE_SEARCH" | "GOOGLE_SEARCH_AND_PARTNERS";
    pageSize?: number;
  }): Promise<KeywordIdea[]> {
    if (!opts.geoTargetIds.length) throw new Error("generateKeywordIdeas: geoTargetIds required");
    if (!opts.keywordSeeds.length) throw new Error("generateKeywordIdeas: keywordSeeds required");

    const cfg = await getGoogleAdsApiConfig().catch(() => null);
    const developerToken = cfg?.developerToken || process.env.GOOGLE_ADS_DEVELOPER_TOKEN;
    if (!developerToken) throw new Error("GOOGLE_ADS_DEVELOPER_TOKEN not configured");

    const accessToken = await this.getAccessToken();
    const url = `${API_BASE}/customers/${this.customerId}:generateKeywordIdeas`;
    const headers: Record<string, string> = {
      Authorization: `Bearer ${accessToken}`,
      "developer-token": developerToken,
      "Content-Type": "application/json",
    };
    if (this.loginCustomerId) headers["login-customer-id"] = this.loginCustomerId;

    const body = {
      language: `languageConstants/${opts.languageId ?? "1000"}`,
      geoTargetConstants: opts.geoTargetIds.map((g) => `geoTargetConstants/${g}`),
      keywordPlanNetwork: opts.network ?? "GOOGLE_SEARCH",
      keywordSeed: { keywords: opts.keywordSeeds.slice(0, 20) }, // API max 20 seeds
      pageSize: opts.pageSize ?? 200,
      includeAdultKeywords: false,
    };

    const res = await fetch(url, {
      method: "POST",
      headers,
      body: JSON.stringify(body),
    });

    if (!res.ok) {
      const text = await res.text();
      throw new Error(
        `Google Ads generateKeywordIdeas failed (${res.status}) for customer ${this.customerId}: ${text.slice(0, 400)}`,
      );
    }

    const json = (await res.json()) as {
      results?: Array<{
        text?: string;
        keywordIdeaMetrics?: {
          avgMonthlySearches?: string;
          competition?: "UNKNOWN" | "UNSPECIFIED" | "LOW" | "MEDIUM" | "HIGH";
          competitionIndex?: string;
          lowTopOfPageBidMicros?: string;
          highTopOfPageBidMicros?: string;
        };
      }>;
    };

    return (json.results ?? []).map((r) => ({
      text: r.text ?? "",
      avgMonthlySearches: Number(r.keywordIdeaMetrics?.avgMonthlySearches ?? 0),
      competition: (r.keywordIdeaMetrics?.competition ?? "UNKNOWN") as KeywordIdea["competition"],
      competitionIndex: Number(r.keywordIdeaMetrics?.competitionIndex ?? 0),
      lowTopOfPageBidMicros: Number(r.keywordIdeaMetrics?.lowTopOfPageBidMicros ?? 0),
      highTopOfPageBidMicros: Number(r.keywordIdeaMetrics?.highTopOfPageBidMicros ?? 0),
    }));
  }
}

export interface KeywordIdea {
  text: string;
  avgMonthlySearches: number;
  competition: "UNKNOWN" | "UNSPECIFIED" | "LOW" | "MEDIUM" | "HIGH";
  /** 0–100. Higher = more competitive. */
  competitionIndex: number;
  lowTopOfPageBidMicros: number;
  highTopOfPageBidMicros: number;
}

export interface AuctionInsightRow {
  /** Competitor domain, e.g. "locksmiths.co.uk" */
  domain: string;
  /**
   * Fraction of auctions where we and the competitor both appeared (0–1).
   * NOTE: Auction Insights shows CO-OCCURRENCE only — not what keywords they
   * bid on, their ad copy, landing page, bid strategy, or negative keywords.
   * Use this to identify who is fighting for the same search slots, not what
   * they're targeting specifically.
   */
  overlapRate: number;
  /** Fraction of auctions where competitor appeared above us (0–1). */
  positionAboveRate: number;
  /** Fraction of auctions where competitor ad appeared at the top of page (0–1). */
  topOfPageRate: number;
  /** Fraction of auctions where competitor ad appeared at absolute top (0–1). */
  absoluteTopOfPageRate: number;
}

export interface HourlyPerformanceRow {
  /** Hour of day (0–23, UTC). */
  hour: number;
  impressions: number;
  clicks: number;
  costMicros: number;
  conversions: number;
  /**
   * Our search impression share during this hour.
   * Use this to detect after-hours gaps — hours where IS drops sharply
   * suggest competitors are pausing campaigns (day-parting opportunity).
   */
  searchImpressionShare: number;
}

/** Resource-name builder helpers (used when chaining mutations). */
export function buildResourceName(
  customerId: string,
  resource: "campaigns" | "campaignBudgets" | "adGroups" | "adGroupAds" | "adGroupCriteria" | "campaignCriteria",
  id: string,
): string {
  return `customers/${stripDashes(customerId)}/${resource}/${id}`;
}

// =========================================================================
// Factory: load credentials from DB
// =========================================================================

/**
 * Construct a GoogleAdsClient from the GoogleAdsAccount DB row. Returns null
 * if the account is missing or inactive (caller decides whether that's fatal).
 */
export async function getGoogleAdsClientForAccount(
  accountId: string,
): Promise<GoogleAdsClient | null> {
  const account = await prisma.googleAdsAccount.findUnique({ where: { id: accountId } });
  if (!account || !account.isActive) return null;

  return new GoogleAdsClient({
    customerId: account.customerId,
    refreshToken: account.refreshToken,
    accessToken: account.accessToken ?? undefined,
    accessTokenExpiresAt: account.tokenExpiresAt ?? undefined,
    loginCustomerId: account.loginCustomerId ?? undefined,
  });
}

/**
 * Returns a client for the first active GoogleAdsAccount, or null. Convenience
 * for single-account setups (which is what we have in Phase 1).
 */
export async function getDefaultGoogleAdsClient(): Promise<{
  client: GoogleAdsClient;
  accountId: string;
  customerId: string;
} | null> {
  const preferredRaw = process.env.GOOGLE_ADS_DEFAULT_CUSTOMER_ID?.trim() || "";
  const preferredCustomerId = preferredRaw.replace(/[^0-9]/g, "");

  let account = preferredCustomerId
    ? await prisma.googleAdsAccount.findFirst({
        where: { isActive: true, customerId: preferredCustomerId },
      })
    : null;

  if (!account) {
    account = await prisma.googleAdsAccount.findFirst({
      where: { isActive: true },
      // Prefer the account that has proven sync activity, then oldest stable fallback.
      orderBy: [{ lastSyncAt: "desc" }, { createdAt: "asc" }],
    });
  }

  if (!account) return null;
  const client = new GoogleAdsClient({
    customerId: account.customerId,
    refreshToken: account.refreshToken,
    accessToken: account.accessToken ?? undefined,
    accessTokenExpiresAt: account.tokenExpiresAt ?? undefined,
    loginCustomerId: account.loginCustomerId ?? undefined,
  });
  return { client, accountId: account.id, customerId: account.customerId };
}

// =========================================================================
// Helpers
// =========================================================================

function stripDashes(id: string): string {
  return id.replace(/[^0-9]/g, "");
}

function assertDateRange(r: DateRange): void {
  const re = /^\d{4}-\d{2}-\d{2}$/;
  if (!re.test(r.since) || !re.test(r.until)) {
    throw new Error(`Invalid GAQL date range: ${r.since}..${r.until}`);
  }
}

/**
 * Coerce an arbitrary string to an integer literal safe for inline use in a
 * GAQL filter (campaign.id etc.). Throws on non-digit input — DO NOT bypass:
 * GAQL has no parameterised queries, so any string interpolation must be
 * pre-validated to prevent injection.
 */
function asInt(s: string): string {
  if (!/^[0-9]+$/.test(s)) throw new Error(`Expected integer, got: ${s}`);
  return s;
}

/**
 * Convert micros (currency * 1,000,000) to a regular currency amount.
 */
export function microsToCurrency(micros: number): number {
  return Math.round((micros / 1_000_000) * 100) / 100;
}
